# collection trigger an error; the . prefix tells Slumber to ignore this field
.base: &base headers: Accept: application/json requests: login: !request <<: *base method: POST url: "{{host}}/anything/login" body: !json { "username": "{{chains.username}}", "password": "{{chains.password}}", } # Folders can be used to keep your recipes organized users: !folder requests: get_user: !request <<: *base name: Get User method: GET url: "{{host}}/anything/current-user" authentication: !bearer "{{chains.auth_token}}" update_user: !request <<: *base name: Update User method: PUT url: "{{host}}/anything/current-user" authentication: !bearer "{{chains.auth_token}}" body: !json { "username": "Kenny" }
